    let minTime = Infinity;
    const m = landStartTime.length;
    const n = waterStartTime.length;

    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            // Case 1: Land first
            const landEnd = landStartTime[i] + landDuration[i];
            const waterStart = waterStartTime[j];
            const case1End = Math.max(landEnd, waterStart) + waterDuration[j];

            // Case 2: Water first
            const waterEnd = waterStartTime[j] + waterDuration[j];
            const landStart = landStartTime[i];
            const case2End = Math.max(waterEnd, landStart) + landDuration[i];

            minTime = Math.min(minTime, case1End, case2End);
        }
    }

    return minTime;
}
